async function main() {
  const csvData = await readFile('transactions.csv');
  const convertedData = convertUsdToEur(csvData, 0.92);
  await writeFile('transactions_eur.csv', convertedData);
}

function convertUsdToEur(csv: string, rate: number): string {
  const lines = csv.split('\n');
  const header = lines[0];
  const rows = lines.slice(1);

  const convertedRows = rows.map(row => {
    const [id, amount] = row.split(',');
    const amountEur = parseFloat(amount) * rate;
    return `${id},${amountEur.toFixed(2)}`;
  });

  return [header, ...convertedRows].join('\n');
}
