interface LogEntry {
  method: string;
  path: string;
  status: number;
}

function parseLogLine(line: string): LogEntry | null {
  const match = line.match(/^(\w+)\s+(\S+)\s+(\d+)$/);
  if (!match) return null;
  return {
    method: match[1],
    path: match[2],
    status: parseInt(match[3], 10),
  };
}

async function appendSummaryRow(summary: { timestamp: string; total: number; errors: number }) {
  const currentReport = await readFile('daily_report.csv');
  const row = `\n${summary.timestamp},${summary.total},${summary.errors}`;
  await writeFile('daily_report.csv', currentReport + row);
}

async function main() {
  const logs = pollSource('http://logs.example.com/access', 1000);
  let totalRequests = 0;
  let errorCount = 0;

  for await (const line of logs) {
    const entry = parseLogLine(line);
    if (entry) {
      totalRequests++;
      if (entry.status >= 400) {
        errorCount++;
      }
    }

    // Append summary every 100 requests
    if (totalRequests > 0 && totalRequests % 100 === 0) {
      await appendSummaryRow({
        timestamp: new Date().toISOString(),
        total: totalRequests,
        errors: errorCount,
      });
      totalRequests = 0;
      errorCount = 0;
    }
  }
}
