async function processTemperature() {
  // Read temperature sensor value
  const reading = await fetchFromApi('https://iot-gateway.local/sensor/temp');

  // Simultaneously push to time-series DB and update dashboard widget
  await Promise.all([
    writeToDatabase('temperature_readings', {
      sensorId: reading.id,
      value: reading.value,
      timestamp: new Date()
    }),
    sendPushNotification('dashboard_widget', `Temp: ${reading.value}°C`)
  ]);

  // Check threshold and trigger HVAC adjustment
  if (reading.value > 30) {
    await fetchFromApi('https://hvac-controller.local/api/adjust', {
      method: 'POST',
      body: JSON.stringify({ mode: 'cool', targetTemp: 22 })
    });
  }
}
