async function processOrder(order: any) {
  await Promise.all([
    reserveInventory(order.items),
    chargePayment(order.paymentMethod),
    sendConfirmationEmail(order.customerEmail, order.id)
  ]);
}

async function reserveInventory(items: any[]) {
  return fetchFromApi('https://api.warehouse.com/reserve', {
    method: 'POST',
    body: JSON.stringify({ items })
  });
}

async function chargePayment(paymentMethod: any) {
  return fetchFromApi('https://api.payment.com/charge', {
    method: 'POST',
    body: JSON.stringify(paymentMethod)
  });
}

