async function main() {
  // 1. Simultaneous Data Collection
  const [twitterData, redditData, hnData] = await Promise.all([
    fetchFromApi('https://api.twitter.com/1.1/search/tweets.json?q=brand'),
    fetchFromApi('https://www.reddit.com/search.json?q=brand'),
    fetchFromApi('https://hacker-news.firebaseio.com/v0/search?q=brand')
  ]);

  // 2. Normalization to common structure
  const normalizeTwitter = (items: any[]) => mapItems(items, (item: any) => ({ text: item.text, source: 'Twitter' }));
  const normalizeReddit = (items: any[]) => mapItems(items, (item: any) => ({ text: item.body, source: 'Reddit' }));
  const normalizeHN = (items: any[]) => mapItems(items, (item: any) => ({ text: item.title, source: 'HackerNews' }));

  const rawMentions = [
    ...normalizeTwitter(twitterData.statuses || []),
    ...normalizeReddit(redditData.data?.children || []),
    ...normalizeHN(hnData.hits || [])
  ];

  // 3. Sentiment Analysis
  const mentionsWithSentiment = await Promise.all(
    rawMentions.map(async (mention) => {
      const sentiment = await llmClassify(mention.text, ['positive', 'negative', 'neutral']);
      return { ...mention, sentiment };
    })
  );

  // 4. Aggregation
  const scoreMap = { positive: 1, negative: -1, neutral: 0 };

  const totalScore = aggregate(
    mentionsWithSentiment,
    (acc, item) => acc + scoreMap[item.sentiment],
    0
  );

  const groupedBySource = groupBy(mentionsWithSentiment, 'source');

  const attribution = mapItems(
    Object.entries(groupedBySource),
    ([source, items]: [string, any[]]) => ({
      source,
      score: aggregate(items, (acc, item) => acc + scoreMap[item.sentiment], 0),
      mentionCount: items.length
    })
  );

  const report = {
    totalScore,
    totalMentions: mentionsWithSentiment.length,
    attribution
  };

  // 5. Output
  await writeToDatabase('brand_sentiment_log', report);
  return report;
}
