async function main() {
  const transactions = await queryDatabase('SELECT * FROM transactions WHERE status = "pending"');

  const results = await Promise.all(
    transactions.map(processTransaction)
  );

  await Promise.all(
    results.map(result => writeToDatabase('fraud_scores', result))
  );
}

async function processTransaction(transaction: any) {
  // Simultaneously check IP geolocation, velocity history, and merchant risk
  const [geoData, velocityHistory, merchantData] = await Promise.all([
    fetchFromApi(`https://api.geo-service.com/ip/${transaction.ipAddress}`),
    queryDatabase(`SELECT * FROM transactions WHERE cardId = '${transaction.cardId}' AND timestamp > NOW() - INTERVAL 1 HOUR`),
    fetchFromApi(`https://api.risk-provider.com/merchant/${transaction.merchantId}`)
  ]);

  const riskScore = calculateRiskScore(geoData, velocityHistory, merchantData);

  return {
    transactionId: transaction.id,
    riskScore,
    details: {
      geoRisk: geoData.riskLevel,
      velocityCount: velocityHistory.length,
      merchantCategory: merchantData.category
    }
  };
}

function calculateRiskScore(geoData: any, velocityHistory: any[], merchantData: any): number {
  let score = 0;

  // Geo Signal
  if (geoData.isProxy || geoData.isTor) score += 40;
  if (geoData.distanceFromBilling > 500) score += 20;

  // Velocity Signal
  const recentTxCount = velocityHistory.length;
  if (recentTxCount > 5) score += 40;
  else if (recentTxCount > 2) score += 20;

  // Merchant Signal
  if (merchantData.category === 'high_risk') score += 30;
  else if (merchantData.category === 'gambling') score += 15;

  return Math.min(score, 100);
}
