```typescript
async function handleRequest(ip: string): Promise<{ status: number }> {
  const now = Date.now();
  const windowMs = 60000;
  const limit = 100;

  // Retrieve existing request timestamps for the client IP
  const records = await queryDatabase(`SELECT timestamps FROM rate_limits WHERE ip = '${ip}'`);
  const timestamps = records.length > 0 ? records[0].timestamps : [];

  // Filter timestamps to keep only those within the 60-second sliding window
  const recentRequests = filterBy(timestamps, (ts: number) => now - ts < windowMs);

  // Check if the client has exceeded the rate limit
  if (recentRequests.length >= limit) {
    return { status: 429 };
  }

  // Add the current request timestamp
  recentRequests.push(now);

  // Persist the updated list of timestamps
  await writeToDatabase('rate_limits', { ip, timestamps: recentRequests });

  return { status: 200 };
}
