type CartItem = { id: string; price: number; quantity: number };
type Cart = { items: CartItem[] };
type CartEvent = { type: 'ADD' | 'REMOVE'; item: CartItem };

let currentCart: Cart = { items: [] };

function updateCart(cart: Cart, event: CartEvent): Cart {
  const existingItemIndex = cart.items.findIndex(i => i.id === event.item.id);

  if (event.type === 'ADD') {
    if (existingItemIndex >= 0) {
      const updatedItems = [...cart.items];
      updatedItems[existingItemIndex] = {
        ...updatedItems[existingItemIndex],
        quantity: updatedItems[existingItemIndex].quantity + event.item.quantity
      };
      return { items: updatedItems };
    }
    return { items: [...cart.items, event.item] };
  }

  if (event.type === 'REMOVE' && existingItemIndex >= 0) {
    const updatedItems = [...cart.items];
    const newQuantity = updatedItems[existingItemIndex].quantity - event.item.quantity;

    if (newQuantity <= 0) {
      updatedItems.splice(existingItemIndex, 1);
    } else {
      updatedItems[existingItemIndex] = { ...updatedItems[existingItemIndex], quantity: newQuantity };
    }
    return { items: updatedItems };
  }

  return cart;
}

function calculateCartSummary(cart: Cart) {
  const subtotal = aggregate(cart.items, (sum, item) => sum + (item.price * item.quantity), 0);
  const tax = subtotal * 0.08;
  const shipping = subtotal > 100 ? 0 : 15;

  return {
    itemCount: aggregate(cart.items, (count, item) => count + item.quantity, 0),
    subtotal,
    tax,
    shipping,
    total: subtotal + tax + shipping
  };
}

async function pushCartUpdate(summary: any) {
  await sendPushNotification(JSON.stringify(summary));
}

async function main() {
  const eventStream = connectWebSocket('wss://api.shop.com/cart-events');

  for await (const event of eventStream) {
    currentCart = updateCart(currentCart, event);
    const summary = calculateCartSummary(currentCart);
    await pushCartUpdate(summary);
  }
}
