type ScoreEvent = { playerId: string; score: number };
type LeaderboardEntry = { playerId: string; score: number };

// Required utility for the specific task
declare function broadcastToClients(leaderboard: LeaderboardEntry[]): Promise<void>;

function updateLeaderboard(current: LeaderboardEntry[], event: ScoreEvent): LeaderboardEntry[] {
  const existingIndex = current.findIndex(e => e.playerId === event.playerId);
  let next = [...current];

  if (existingIndex >= 0) {
    // Update score if the new one is higher
    if (event.score > next[existingIndex].score) {
      next[existingIndex] = { playerId: event.playerId, score: event.score };
    }
  } else {
    // Add new player
    next.push({ playerId: event.playerId, score: event.score });
  }

  // Sort descending and keep top 10
  return next
    .sort((a, b) => b.score - a.score)
    .slice(0, 10);
}

function hasChanged(oldList: LeaderboardEntry[], newList: LeaderboardEntry[]): boolean {
  return JSON.stringify(oldList) !== JSON.stringify(newList);
}

async function main() {
  const scoreStream = connectWebSocket('wss://api.game.com/events');
  let leaderboard: LeaderboardEntry[] = [];

  for await (const event of scoreStream) {
    const nextLeaderboard = updateLeaderboard(leaderboard, event);

    if (hasChanged(leaderboard, nextLeaderboard)) {
      leaderboard = nextLeaderboard;
      await broadcastToClients(leaderboard);
    }
  }
}
