```typescript
// State management
const circuitState = {
  status: 'CLOSED' as 'CLOSED' | 'OPEN' | 'HALF_OPEN',
  failureCount: 0,
  requestCount: 0,
  windowStart: Date.now(),
  lastFailureTime: 0
};

const WINDOW_MS = 30000;
const FAILURE_THRESHOLD = 0.5;
const RECOVERY_TIMEOUT_MS = 10000;

function resetWindowIfExpired() {
  const now = Date.now();
  if (now - circuitState.windowStart > WINDOW_MS) {
    circuitState.failureCount = 0;
    circuitState.requestCount = 0;
    circuitState.windowStart = now;
  }
}

function getDegradedResponse() {
  return { status: 503, message: 'Service unavailable (Circuit Breaker Open)' };
}

async function sendPaymentRequest(paymentData: any) {
  resetWindowIfExpired();
  const now = Date.now();

  // Handle OPEN state
  if (circuitState.status === 'OPEN') {
    if (now - circuitState.lastFailureTime > RECOVERY_TIMEOUT_MS) {
      circuitState.status = 'HALF_OPEN';
    } else {
      return getDegradedResponse();
    }
  }

  // Handle HALF_OPEN state (Probe)
  if (circuitState.status === 'HALF_OPEN') {
    try {
      const response = await fetchFromApi('https://api.payment-gateway.com/charge', {
        method: 'POST',
        body: JSON.stringify(paymentData)
      });

      if (response.status >= 400) throw new Error('Gateway error');

      // Probe successful: Close circuit
      circuitState.status = 'CLOSED';
      circuitState.failureCount = 0;
      circuitState.requestCount = 0;
      return response;
    } catch (error) {
      // Probe failed: Reopen circuit
      circuitState.status = 'OPEN';
      circuitState.lastFailureTime = now;
      return getDegradedResponse();
    }
  }

  // Handle CLOSED state (Normal Operation)
  try {
    const response = await fetchFromApi('https://api.payment-gateway.com/charge', {
      method: 'POST',
      body: JSON.stringify(paymentData)
    });

    if (response.status >= 400) throw new Error('Gateway error');

    circuitState.requestCount++;
    return response;
  } catch (error) {
    circuitState.requestCount++;
    circuitState.failureCount++;

    if (circuitState.failureCount / circuitState.requestCount > FAILURE_THRESHOLD) {
      circuitState.status = 'OPEN';
      circuitState.lastFailureTime = now;
    }
    throw error;
  }
}
