async function triggerPagerDuty(incident: any) {
  await fetchFromApi('https://api.pagerduty.com/incidents', {
    method: 'POST',
    body: JSON.stringify(incident),
  });
}

async function updateDashboard(data: any) {
  await writeToDatabase('system_status', data);
}

async function monitorMetrics() {
  const stream = connectWebSocket('wss://metrics.stream/live');

  for await (const metrics of stream) {
    const errorRate = metrics.errors / metrics.totalRequests;

    if (errorRate > 0.05) {
      const alertData = {
        errorRate,
        timestamp: new Date().toISOString(),
        details: metrics
      };

      await Promise.all([
        triggerPagerDuty(alertData),
        logToAudit({ event: 'HIGH_ERROR_RATE', ...alertData }),
        updateDashboard({ status: 'CRITICAL', ...alertData })
      ]);
    }
  }
}
